$$[{"id":"f1-hero","type":"Hero","data":{"headline":"Holi","subheadline":"The festival of colour, love and spring. A morning that turns whole towns into a swirl of pink, gold and laughter.","backgroundImage":"","ctaText":"Plan My Journey","ctaLink":"/enquire"}},{"id":"f1-facts","type":"Fact Bar","data":{"facts":[{"label":"When","value":"March"},{"label":"Where","value":"Mathura, Vrindavan and Barsana, Uttar Pradesh; Jaipur and Udaipur, Rajasthan"}]}},{"id":"f1-tiles","type":"Tiles","data":{"heading":"How we celebrate it with you","tiles":[{"title":"The colour throw","description":"Join the crowds, or watch from a calm rooftop, as colour fills the air."},{"title":"Barsana traditions","description":"The famous, joyful Lathmar Holi in the towns near Mathura."},{"title":"A gentler Holi","description":"A private, family style celebration if the crowds feel too much."}]}},{"id":"f1-places","type":"Place Chips","data":{"heading":"Best cities","places":[{"name":"Mathura","region":"Uttar Pradesh"},{"name":"Vrindavan","region":"Uttar Pradesh"},{"name":"Barsana","region":"Uttar Pradesh"},{"name":"Jaipur","region":"Rajasthan"},{"name":"Udaipur","region":"Rajasthan"},{"name":"Pushkar","region":"Rajasthan"}]}},{"id":"f1-faq","type":"FAQ","data":{"heading":"Questions, answered simply","subtitle":"The practical questions about visiting India for Holi, answered in plain English.","items":[{"question":"Is Holi safe for travellers?","answer":"Yes, when planned correctly. We ensure you experience the joy of Holi while staying comfortable, with vetted guides, private transport and carefully chosen viewing spots."},{"question":"How far in advance should I plan a Holi trip?","answer":"At least six to nine months. The best heritage stays and guides book out quickly around major festivals like Holi."},{"question":"Will Holi be too crowded?","answer":"Festivals are busy, but we balance the energy of the crowds with quiet retreats. You can join the heart of the action when you want, and step back when you need to."},{"question":"Can I combine Holi with a longer journey?","answer":"Absolutely. Holi is often the focal point of a longer journey through India, giving you a balance of celebration and slow travel."}]}},{"id":"f1-cta","type":"CTA Banner","data":{"headline":"Join the celebration","body":"We arrange the timing and details. Tell us your travel window.","buttonLabel":"Plan my journey","buttonLink":"/enquire"}}]$$::jsonb,
$${"title":"Holi | MANNYAM","description":"The festival of colour, love and spring. A morning that turns whole towns into a swirl of pink, gold and laughter.","canonical_url":"https://mannyam.in/festival-holi"}$$::jsonb),

